const data = $input.first().json;
const workflowName = data.workflow?.name || 'Unknown Workflow';
const workflowId = data.workflow?.id || '';
const executionId = data.execution?.id || '';
const errorMessage = data.error?.message || 'Unknown error';
const errorNode = data.error?.node?.name || data.lastNodeExecuted || 'Unknown node';
const executionUrl = data.execution?.url || ('https://omar7055.app.n8n.cloud/workflow/' + workflowId + '/executions/' + executionId);
const now = new Date().toLocaleString('en-US', { timeZone: 'Africa/Cairo', dateStyle: 'full', timeStyle: 'medium' });
const workflowNumber = workflowName.includes('1') ? '1' : workflowName.includes('2') ? '2' : workflowName.includes('3') ? '3' : '?';
const subject = '🚨 Error in ' + workflowName + ' — Node: ' + errorNode;
const html = `
<div style='font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#f5f5f5;padding:20px;'>
  <div style='background:#ff4d6d;padding:20px 24px;border-radius:8px 8px 0 0;'>
    <h1 style='color:#fff;margin:0;font-size:20px;'>🚨 Workflow Error Detected</h1>
    <p style='color:rgba(255,255,255,0.8);margin:4px 0 0;font-size:13px;'>Match Analyst Platform — Automated Alert</p>
  </div>
  <div style='background:#fff;padding:24px;border-radius:0 0 8px 8px;border:1px solid #e0e0e0;border-top:none;'>
    <table style='width:100%;border-collapse:collapse;'>
      <tr><td style='padding:10px 0;border-bottom:1px solid #f0f0f0;width:160px;'><strong style='color:#666;font-size:13px;'>Workflow</strong></td><td style='padding:10px 0;border-bottom:1px solid #f0f0f0;font-size:14px;color:#1a1a1a;'>${workflowName}</td></tr>
      <tr><td style='padding:10px 0;border-bottom:1px solid #f0f0f0;'><strong style='color:#666;font-size:13px;'>Workflow #</strong></td><td style='padding:10px 0;border-bottom:1px solid #f0f0f0;font-size:14px;color:#1a1a1a;'>Workflow ${workflowNumber}</td></tr>
      <tr><td style='padding:10px 0;border-bottom:1px solid #f0f0f0;'><strong style='color:#666;font-size:13px;'>Failed Node</strong></td><td style='padding:10px 0;border-bottom:1px solid #f0f0f0;'><span style='background:#fff0f2;color:#ff4d6d;padding:2px 8px;border-radius:4px;font-size:13px;font-family:monospace;border:1px solid #ffc0cb;'>${errorNode}</span></td></tr>
      <tr><td style='padding:10px 0;border-bottom:1px solid #f0f0f0;'><strong style='color:#666;font-size:13px;'>Error Message</strong></td><td style='padding:10px 0;border-bottom:1px solid #f0f0f0;font-size:13px;color:#cc0000;font-family:monospace;'>${errorMessage}</td></tr>
      <tr><td style='padding:10px 0;border-bottom:1px solid #f0f0f0;'><strong style='color:#666;font-size:13px;'>Execution ID</strong></td><td style='padding:10px 0;border-bottom:1px solid #f0f0f0;font-size:13px;color:#666;font-family:monospace;'>#${executionId}</td></tr>
      <tr><td style='padding:10px 0;'><strong style='color:#666;font-size:13px;'>Time (Cairo)</strong></td><td style='padding:10px 0;font-size:13px;color:#1a1a1a;'>${now}</td></tr>
    </table>
    <div style='margin-top:24px;'>
      <a href='${executionUrl}' style='background:#1a1a1a;color:#fff;padding:12px 20px;border-radius:6px;text-decoration:none;font-size:13px;display:inline-block;'>View Execution in n8n →</a>
    </div>
    <p style='margin-top:20px;font-size:12px;color:#999;'>This alert was sent automatically by your Match Analyst error monitoring workflow.</p>
  </div>
</div>`;
return [{ json: { subject, html, workflowName, errorNode, errorMessage, executionUrl } }];
